from dataclasses import dataclass, field

@dataclass
class BlueprintReviewChecklist:
    """Pre-release sign-off checklist derived from the blueprint."""
    guardrails_implemented:   list[str]    # names of GuardrailSpec that are live
    guardrails_pending:       list[str]    # names that are not yet wired up
    metrics_emitting:         list[str]    # ObservabilitySpec metrics confirmed in staging
    metrics_missing:          list[str]
    latency_budgets_verified: bool
    human_gate_tested:        bool
    pii_strip_tested:         bool

    def is_release_ready(self) -> bool:
        return (
            len(self.guardrails_pending) == 0
            and len(self.metrics_missing) == 0
            and self.latency_budgets_verified
            and self.human_gate_tested
            and self.pii_strip_tested
        )

    def blocking_issues(self) -> list[str]:
        issues = []
        if self.guardrails_pending:
            issues.append(f"Unimplemented guardrails: {self.guardrails_pending}")
        if self.metrics_missing:
            issues.append(f"Missing observability metrics: {self.metrics_missing}")
        if not self.latency_budgets_verified:
            issues.append("Latency budgets not verified in staging")
        if not self.human_gate_tested:
            issues.append("Human review gate not tested end-to-end")
        if not self.pii_strip_tested:
            issues.append("PII strip pass not tested with synthetic PII data")
        return issues
